const today = new Date().toISOString().split('T')[0];

// Get data from all 3 sources
const callItems = $('Get Call Log').all();
const apptItems = $('Get Appointments').all();
const escalItems = $('Get Escalations').all();

// Filter today's data
const todayCalls = callItems.filter(i => (i.json.timestamp || '').startsWith(today));
const todayAppts = apptItems.filter(i => (i.json.appointment_date || '').startsWith(today) || (i.json.created_at || '').startsWith(today));
const todayEscalations = escalItems.filter(i => (i.json.timestamp || '').startsWith(today));

// Calculate metrics
const totalCalls = todayCalls.length;
const callsByIntent = {};
todayCalls.forEach(c => {
  const intent = c.json.intent || 'unknown';
  callsByIntent[intent] = (callsByIntent[intent] || 0) + 1;
});

const newBookings = todayAppts.filter(a => a.json.status === 'confirmed' && (a.json.created_at || '').startsWith(today)).length;
const cancellations = todayAppts.filter(a => a.json.status === 'cancelled' && (a.json.cancelled_at || '').startsWith(today)).length;
const noShows = todayAppts.filter(a => a.json.status === 'no_show').length;
const completed = todayAppts.filter(a => a.json.showed_up === 'yes').length;
const totalScheduled = todayAppts.filter(a => (a.json.appointment_date || '').startsWith(today)).length;

const escalationCount = todayEscalations.length;
const highPriority = todayEscalations.filter(e => e.json.priority === 'high').length;

// Upcoming tomorrow
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowStr = tomorrow.toISOString().split('T')[0];
const tomorrowAppts = apptItems.filter(i => (i.json.appointment_date || '').startsWith(tomorrowStr) && i.json.status === 'confirmed').length;

// Calculate total call duration
const totalDuration = todayCalls.reduce((sum, c) => sum + (parseInt(c.json.duration) || 0), 0);
const avgDuration = totalCalls > 0 ? Math.round(totalDuration / totalCalls) : 0;

// Show rate
const showRate = totalScheduled > 0 ? Math.round((completed / totalScheduled) * 100) : 0;

const report = {
  date: today,
  total_calls: totalCalls,
  calls_by_intent: callsByIntent,
  new_bookings: newBookings,
  cancellations: cancellations,
  no_shows: noShows,
  completed_appointments: completed,
  total_scheduled: totalScheduled,
  show_rate: showRate,
  escalations: escalationCount,
  high_priority_escalations: highPriority,
  avg_call_duration_sec: avgDuration,
  total_call_duration_min: Math.round(totalDuration / 60),
  tomorrow_appointments: tomorrowAppts
};

// Build HTML report
const intentRows = Object.entries(callsByIntent).map(([k,v]) => `<tr><td style='padding:6px 12px;border-bottom:1px solid #f0f0f0;'>${k}</td><td style='padding:6px 12px;border-bottom:1px solid #f0f0f0;text-align:right;'>${v}</td></tr>`).join('');

const html = `<div style='font-family:Arial,sans-serif;max-width:640px;margin:0 auto;'>
<h1 style='color:#1e293b;font-size:24px;margin-bottom:4px;'>Daily Operations Report</h1>
<p style='color:#64748b;margin-top:0;'>${new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>

<div style='display:flex;gap:12px;margin:20px 0;flex-wrap:wrap;'>
  <div style='flex:1;min-width:120px;background:#eff6ff;border-radius:8px;padding:16px;text-align:center;'><div style='font-size:28px;font-weight:bold;color:#2563eb;'>${totalCalls}</div><div style='color:#64748b;font-size:13px;'>Total Calls</div></div>
  <div style='flex:1;min-width:120px;background:#f0fdf4;border-radius:8px;padding:16px;text-align:center;'><div style='font-size:28px;font-weight:bold;color:#16a34a;'>${newBookings}</div><div style='color:#64748b;font-size:13px;'>New Bookings</div></div>
  <div style='flex:1;min-width:120px;background:#fef2f2;border-radius:8px;padding:16px;text-align:center;'><div style='font-size:28px;font-weight:bold;color:#dc2626;'>${noShows}</div><div style='color:#64748b;font-size:13px;'>No-Shows</div></div>
  <div style='flex:1;min-width:120px;background:#fefce8;border-radius:8px;padding:16px;text-align:center;'><div style='font-size:28px;font-weight:bold;color:#ca8a04;'>${cancellations}</div><div style='color:#64748b;font-size:13px;'>Cancellations</div></div>
</div>

<h3 style='color:#1e293b;border-bottom:2px solid #e2e8f0;padding-bottom:8px;'>Appointments</h3>
<table style='width:100%;border-collapse:collapse;'>
  <tr><td style='padding:6px 0;color:#64748b;'>Scheduled Today</td><td style='text-align:right;font-weight:bold;'>${totalScheduled}</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Completed</td><td style='text-align:right;font-weight:bold;color:#16a34a;'>${completed}</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Show Rate</td><td style='text-align:right;font-weight:bold;'>${showRate}%</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Tomorrow's Appointments</td><td style='text-align:right;font-weight:bold;color:#2563eb;'>${tomorrowAppts}</td></tr>
</table>

<h3 style='color:#1e293b;border-bottom:2px solid #e2e8f0;padding-bottom:8px;margin-top:24px;'>Calls by Intent</h3>
<table style='width:100%;border-collapse:collapse;'>${intentRows || '<tr><td style="color:#94a3b8;padding:12px;">No calls today</td></tr>'}</table>

<h3 style='color:#1e293b;border-bottom:2px solid #e2e8f0;padding-bottom:8px;margin-top:24px;'>Call Stats</h3>
<table style='width:100%;border-collapse:collapse;'>
  <tr><td style='padding:6px 0;color:#64748b;'>Avg Call Duration</td><td style='text-align:right;'>${avgDuration}s</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Total Call Time</td><td style='text-align:right;'>${Math.round(totalDuration / 60)} min</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Escalations</td><td style='text-align:right;${escalationCount > 0 ? "color:#dc2626;font-weight:bold;" : ""}'>${escalationCount}${highPriority > 0 ? ` (${highPriority} high priority)` : ''}</td></tr>
</table>

<div style='margin-top:24px;padding:16px;background:#f8fafc;border-radius:8px;border:1px solid #e2e8f0;text-align:center;color:#64748b;font-size:13px;'>Generated by Dental AI Voice Receptionist</div>
</div>`;

return [{ json: { ...report, html_report: html } }];
